import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Deal {
  product: string;
  discount: number;
  expiry: string;
}

interface WidgetData {
  topDeals: Deal[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { topDeals } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FF5722', fontWeight: 600 }}>
            Top Deals
          </Typography>

          <Stack spacing={1.5}>
            {topDeals.map((deal, index) => (
              <Box key={index} sx={{ bgcolor: '#2C2C2C', p: 1.5, borderRadius: 1 }}>
                <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {deal.product}
                </Typography>
                <Stack direction="row" alignItems="center" spacing={1} sx={{ mt: 0.5 }}>
                  <Chip label={`${deal.discount}% Off`} sx={{ bgcolor: '#FF5722', color: '#FFFFFF', fontSize: '12px' }} />
                  <Typography variant="caption" sx={{ color: '#B0B0B0' }}>
                    Expires: {new Date(deal.expiry).toLocaleDateString()}
                  </Typography>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
